diff --git a/src/FluentValidation/DefaultValidatorOptions.cs b/src/FluentValidation/DefaultValidatorOptions.cs
index fd30941..cab5814 100644
--- a/src/FluentValidation/DefaultValidatorOptions.cs
+++ b/src/FluentValidation/DefaultValidatorOptions.cs
@@ -163,7 +163,32 @@ public static class DefaultValidatorOptions {
 	}

 	/// <summary>
-	/// Specifies a condition limiting when the validator should run.
+	/// Specifies a delegate that derives a custom error code at validation time.
+	/// </summary>
+	/// <param name="rule">The current rule</param>
+	/// <param name="codeProvider">Delegate that receives the object being validated and returns the error code.</param>
+	/// <returns></returns>
+	public static IRuleBuilderOptions<T, TProperty> WithErrorCode<T, TProperty>(this IRuleBuilderOptions<T, TProperty> rule, Func<T, string> codeProvider) {
+		ArgumentNullException.ThrowIfNull(codeProvider);
+		Configurable(rule).Current.ErrorCodeProvider = (ctx, _) =>
+			codeProvider(ctx == null ? default : ctx.InstanceToValidate);
+		return rule;
+	}
+
+	/// <summary>
+	/// Specifies a delegate that derives a custom error code at validation time using both the instance and the property value.
+	/// </summary>
+	/// <param name="rule">The current rule</param>
+	/// <param name="codeProvider">Delegate that receives the object being validated and the property value and returns the error code.</param>
+	/// <returns></returns>
+	public static IRuleBuilderOptions<T, TProperty> WithErrorCode<T, TProperty>(this IRuleBuilderOptions<T, TProperty> rule, Func<T, TProperty, string> codeProvider) {
+		ArgumentNullException.ThrowIfNull(codeProvider);
+		Configurable(rule).Current.ErrorCodeProvider = (ctx, value) =>
+			codeProvider(ctx == null ? default : ctx.InstanceToValidate, value);
+		return rule;
+	}
+
diff --git a/src/FluentValidation/Internal/RuleBase.cs b/src/FluentValidation/Internal/RuleBase.cs
